        name = project['Project_Name'].lower()
        if 'design' in name:
            project['Status'] = 'design'
        elif 'repair' in name and 'completed' not in name:
            project['Status'] = 'construction'
        else:
            project['Status'] = 'not started'

print('__RESULT__:')
